import Sidebar from '../components/Sidebar';
import startImage from '../assets/mainpage.png';

function NewsPage() {
  return (
    <div className="relative w-full min-h-screen bg-white overflow-hidden">
      {/* 흐릿한 배경 이미지 */}
      <img
        src={startImage}
        alt="배경"
        className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[80%] h-[80%]  object-cover"
      />

      {/* 레이아웃: 사이드바 + 메인 */}
      <div className="relative z-10 flex px-8 pt-12 items-start">
        {/* 사이드바 */}
        <Sidebar />

        {/* 메인 콘텐츠 */}
        <main className="flex-1 px-8">
          {/* 제목 */}
          <h2 className="text-2xl font-bold text-gray-800 mb-8 mt-8">소식</h2>

          {/* 소식 리스트 */}
          <div className="space-y-6">
            {[1, 2, 3].map((i) => (
              <div
                key={i}
                className="bg-white/80 backdrop-blur-sm border border-blue-200 shadow-sm rounded-xl p-6 hover:shadow-md transition"
              >
                <div className="flex justify-between items-center mb-2">
                  <h3 className="text-lg font-semibold text-gray-800">
                    🔔 주요 공지 제목 {i}
                  </h3>
                  <span className="text-sm text-gray-500">2024-04-{i + 17}</span>
                </div>
                <p className="text-gray-600 text-sm">
                  공지사항 요약 내용입니다. 상세한 공지나 업데이트 내용이 여기에 들어갑니다.
                </p>
              </div>
            ))}
          </div>
        </main>
      </div>
    </div>
  );
}

export default NewsPage;
